#!/usr/bin/env node
const fs=require('fs'),path=require('path');const root=path.resolve(__dirname,'..'),dist=path.join(root,'dist'),fail=[];const read=f=>fs.existsSync(f)?fs.readFileSync(f,'utf8'):'';function assert(c,m){if(!c)fail.push(m)}
const index=read(path.join(dist,'index.html'));assert(index,'dist/index.html não existe.');const assets=fs.existsSync(path.join(dist,'assets'))?fs.readdirSync(path.join(dist,'assets')).filter(f=>/^app\..*\.js$/.test(f)):[];assert(assets.length,'dist/assets/app.*.js não existe.');const bundle=assets.map(f=>read(path.join(dist,'assets',f))).join('\n');
assert(/STORAGE_MODE:\s*'firebase'/.test(bundle),'bundle não contém STORAGE_MODE firebase.');assert(/projectId:\s*'gestordepesquisa'/.test(bundle),'bundle não contém projectId gestordepesquisa.');assert(/firebase\.initializeApp/.test(bundle),'bundle não contém firebase.initializeApp.');
const all=index+'\n'+bundle;['firebase-app-compat.js','firebase-auth-compat.js','firebase-firestore-compat.js','firebase-functions-compat.js'].forEach(s=>assert(all.includes(s)||bundle.includes('window.firebase'),`SDK compat ausente: ${s}`));
const order=['config.js','firebase-init.js','firebase-repository.js','repository.js','app.js'];let last=-1;for(const name of order){const i=bundle.indexOf(`/* ${name} */`);if(i===-1){if(name==='repository.js'&&bundle.includes('/* repository.js */')){}else fail.push(`marcador ausente no bundle: ${name}`);}else{if(i<last)fail.push(`ordem incorreta: ${name}`);last=i;}}
if(fail.length){console.error(fail.join('\n'));process.exit(1)}console.log('validate-firebase-bundle: PASS');
